VALUES
  ('optician-moex-00799', 'optician', 'optician-moex-111-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '若受檢者為正視眼，在其眼前加上交叉圓柱鏡，白點位於鏡片水平方向，於視網膜呈現的狀況為何？', '["垂直方向的光線聚焦在視網膜之前，形成一條水平焦線", "垂直方向的光線聚焦在視網膜之後，形成一條水平焦線", "垂直方向的光線聚焦在視網膜之後，形成一條垂直焦線", "垂直方向的光線聚焦在視網膜之前，形成一條垂直焦線"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "898af7d6caca", "answer_pdf_sha1": "1ed372d5a357", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1007", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 41, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00800', 'optician', 'optician-moex-111-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '受檢者看遠有+2.00DS的遠視，戴上全矯正眼鏡後進行測試，使用推進法測得近點為20cm，調節幅度應 為多少？', '["3.00D", "5.00D", "7.00D", "7.50D"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "898af7d6caca", "answer_pdf_sha1": "1ed372d5a357", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1007", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 42, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00801', 'optician', 'optician-moex-111-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '關於融像性交叉圓柱鏡（fusedcrosscylinder,FCC）測驗，下列說明何者錯誤？', '["屬於近方試驗，應該給予充分照明", "一般設置是將交叉圓柱鏡的負散光軸設置在90度處", "如在測驗剛開始時，當受測者反應直線條較為清晰，可嘗試翻轉交叉圓柱鏡；如果翻轉後依然表示直線 較清楚，記錄為垂直偏好（verticalpreference）", "非老花眼者由於景深效應，可能依然會有些微調節遲滯，約為+0.50D"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "898af7d6caca", "answer_pdf_sha1": "1ed372d5a357", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1007", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 43, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00802', 'optician', 'optician-moex-111-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '有關老花眼的敘述，下列何者正確？', '["男人老花眼的年紀一般較女人來得早", "相同的矯正鏡片度數下，近視眼的人若戴眼鏡，其老花症狀較戴隱形眼鏡來得早", "未矯正的遠視眼老花的症狀較未矯正的近視眼來得早", "瞳孔較小的人老花症狀較瞳孔大的人來得早"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "898af7d6caca", "answer_pdf_sha1": "1ed372d5a357", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1007", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 44, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00803', 'optician', 'optician-moex-111-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '距離受檢者40cm處進行諾特動態檢影（Nottdynamicretinoscopy），以平行光觀察到眼睛的檢影反射光為 順動（withmotion），下列何者正確？', '["靠近受檢者，縮短檢影工作距離以找到中和點", "遠離受檢者，拉長檢影工作距離以找到中和點", "放入正球面（plus）鏡中和反射光", "放入負球面（minus）鏡中和反射光"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "898af7d6caca", "answer_pdf_sha1": "1ed372d5a357", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1007", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 45, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00804', 'optician', 'optician-moex-111-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '有關動態視網膜檢影鏡單眼評估法（monocularestimationmethod,MEM）的敘述，下列何者錯誤？', '["可用於測量調節反應（accommodativeresponse）與診斷雙眼視覺異常", "檢查時要求受檢者注視嵌附在檢影鏡上之視標", "操作過程中無須遮蓋單眼", "若見順動光影，逐漸加多正球面度鏡片，留置於綜合驗光儀或試鏡架上，直至中和"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "898af7d6caca", "answer_pdf_sha1": "1ed372d5a357", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1007", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 46, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00805', 'optician', 'optician-moex-111-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '調節刺激（accommodativestimulus）與調節反應（accommodativeresponse）多數情形下並非完全同步，但 因下列何項功能、效應，影像仍然相對清晰可以接受？', '["焦深（depthoffocus）", "調節靈敏度（accommodativefacility）", "史特爾姆間隔（intervalofSturm）", "對比敏感度（contrastsensitivity）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "898af7d6caca", "answer_pdf_sha1": "1ed372d5a357", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1007", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 47, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00806', 'optician', 'optician-moex-111-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '對於46歲有近視-0.50D的患者，置入遠用處方與暫時加入度（+0.75D）於綜合驗光儀後，於40cm標準 距離執行正相對調節（positiverelativeaccommodation,PRA）與負相對調節（negativerelativeaccommodation, NRA）檢查，結果如下：NRA/PRA：+1.75/-1.25。調節平衡後，此患者在40cm的近用處方為何？', '["+0.50DS", "+1.00DS", "+1.50DS", "+1.75DS"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "898af7d6caca", "answer_pdf_sha1": "1ed372d5a357", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1007", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 48, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00807', 'optician', 'optician-moex-111-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '使用推進法與拉遠法測量調節幅度（amplitudeofaccommodation：push-upmethodandpull-awaymethod） 時，下列敘述何者正確？', '["測量調節近點或遠點的距離依據，是以視標卡至角膜平面為基準", "記錄檢測結果時不是以公尺，而是以公分為單位", "為單眼進行測試", "於Hofstetter’s公式中，期望幅度最小值為18.5-（0.25×年齡）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "898af7d6caca", "answer_pdf_sha1": "1ed372d5a357", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1007", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 49, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00808', 'optician', 'optician-moex-111-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '正視眼用負鏡片測量眼球調節幅度，在40cm距離用了-2.00D時，受檢者表示視標開始模糊，無法持續看 清楚。則此眼的調節幅度是多少？', '["1.50D", "2.50D", "3.50D", "4.50D"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "898af7d6caca", "answer_pdf_sha1": "1ed372d5a357", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1007", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 50, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
